elements.content:
graph LR
  Client["Mobile app"] -->|"POST /feed"| Gateway["API gateway"]
  Gateway --> Services["Internal services"]

  classDef base fill:#111827,stroke:#334155,color:#e5e7eb,stroke-width:1px;
  classDef hot fill:#0f172a,stroke:#38bdf8,color:#ffffff,stroke-width:3px;
  class Client,Gateway,Services base;

graph LR
  Client["Mobile app"] --> Gateway["API gateway"]
  Gateway --> RateLimiter["Rate limiter"]
  Gateway --> AuthService["Auth service"]
  RateLimiter --> Decision["Allow or block"]
  AuthService --> Decision
  Decision --> AppServices["App services"]

  classDef base fill:#111827,stroke:#334155,color:#e5e7eb,stroke-width:1px;
  classDef guard fill:#1e1b4b,stroke:#a78bfa,color:#ffffff,stroke-width:3px;
  class Client,Gateway,RateLimiter,AuthService,Decision,AppServices base;

graph TD
  Gateway["API gateway"] --> Token["Access token"]
  Token --> AuthService["Auth service"]
  AuthService -->|"valid"| Identity["User identity"]
  AuthService -->|"invalid"| Deny["Deny response"]
  Identity --> NextService["Next service"]

  classDef base fill:#111827,stroke:#334155,color:#e5e7eb,stroke-width:1px;
  classDef success fill:#052e16,stroke:#22c55e,color:#ffffff,stroke-width:3px;
  classDef danger fill:#450a0a,stroke:#ef4444,color:#ffffff,stroke-width:3px;
  class Gateway,Token,AuthService,Identity,Deny,NextService base;

graph LR
  Gateway["API gateway"] --> PostService["Post service"]
  PostService --> PostDB["Post database"]
  PostService --> MediaStorage["Object storage"]
  PostService --> EventBus["Event stream"]
  EventBus --> FeedBuilder["Feed builder"]
  EventBus --> Notifications["Notifications"]

  classDef base fill:#111827,stroke:#334155,color:#e5e7eb,stroke-width:1px;
  classDef write fill:#431407,stroke:#fb923c,color:#ffffff,stroke-width:3px;
  class Gateway,PostService,PostDB,MediaStorage,EventBus,FeedBuilder,Notifications base;
